type ExampleElementConfig = {
  sequenceNumber: number;
  type: Element["type"];
  content: Element["content"];
  isNew?: Element["is_new"];
  stream_audio_start_delay_ms?: number;
  stream_audio_segment_interval_ms?: number;
} & Partial<Omit<Element, "sequence_number" | "type" | "content" | "is_new">>;

type StreamingStoryElement = Element & {
  stream_audio_start_delay_ms?: number;
  stream_audio_segment_interval_ms?: number;
};

const STREAM_INITIAL_DELAY_MS = 600;
const STREAM_ELEMENT_PAUSE_MS = 500;
const STREAM_TEXT_CHAR_DELAY_MS = 24;
const STREAM_MARKUP_CHAR_DELAY_MS = 8;
const STREAM_AUDIO_SEGMENT_INTERVAL_MS = 2200;

const canStreamElementContent = (
  element: Element
): element is Element & { content: string } =>
  typeof element.content === "string";

const getStreamCharacterDelay = (element: Element) => {
  if (["html", "svg"].includes(String(element.type))) {
    return STREAM_MARKUP_CHAR_DELAY_MS;
  }

  if (element.type === "interaction") {
    return STREAM_TEXT_CHAR_DELAY_MS + 8;
  }

  return STREAM_TEXT_CHAR_DELAY_MS;
};

const getVisibleAudioSegmentCount = (
  element: StreamingStoryElement,
  elapsedMs: number
) => {
  if (element.type !== "text") {
    return element.audio_segments?.length ?? 0;
  }

  const totalSegmentCount = element.audio_segments?.length ?? 0;
  const audioStartDelayMs = Math.max(
    element.stream_audio_start_delay_ms ?? 0,
    0
  );
  const audioSegmentIntervalMs = Math.max(
    element.stream_audio_segment_interval_ms ??
      STREAM_AUDIO_SEGMENT_INTERVAL_MS,
    1
  );

  if (totalSegmentCount === 0) {
    return 0;
  }

  if (elapsedMs < audioStartDelayMs) {
    return 0;
  }

  return Math.min(
    totalSegmentCount,
    1 +
      Math.floor(
        Math.max(elapsedMs - audioStartDelayMs, 0) / audioSegmentIntervalMs
      )
  );
};

const shouldStreamAudioSegments = (element: StreamingStoryElement) =>
  element.type === "text" && (element.audio_segments?.length ?? 0) > 0;

const getNextAudioSegmentDelay = (
  element: StreamingStoryElement,
  elapsedMs: number,
  visibleAudioSegmentCount: number
) => {
  const audioStartDelayMs = Math.max(
    element.stream_audio_start_delay_ms ?? 0,
    0
  );
  const audioSegmentIntervalMs = Math.max(
    element.stream_audio_segment_interval_ms ??
      STREAM_AUDIO_SEGMENT_INTERVAL_MS,
    1
  );
  const nextVisibleAt =
    visibleAudioSegmentCount <= 0
      ? audioStartDelayMs
      : audioStartDelayMs + visibleAudioSegmentCount * audioSegmentIntervalMs;

  return Math.max(80, nextVisibleAt - Math.max(elapsedMs, 0));
};

const buildStreamedElement = (
  element: StreamingStoryElement,
  content: Element["content"],
  isElementComplete: boolean,
  visibleAudioSegmentCount: number = 0
): Element => {
  const nextAudioSegments = isElementComplete
    ? element.audio_segments
    : (element.audio_segments ?? []).slice(0, visibleAudioSegmentCount);

  return {
    ...element,
    content,
    is_renderable: true,
    // Keep speakable intent so Slide can surface buffering before audio arrives.
    is_speakable: element.is_speakable,
    audio_url: isElementComplete ? element.audio_url : "",
    audio_segments: nextAudioSegments,
  };
};

const StreamingSlidePreview = ({
  elementList = [],
  ...props
}: React.ComponentProps<typeof Slide>) => {
  const [streamedElementList, setStreamedElementList] = useState<Element[]>([]);

  const stableElementList = useMemo(
    () => elementList as StreamingStoryElement[],
    [elementList]
  );

  useEffect(() => {
    if (stableElementList.length === 0) {
      setStreamedElementList([]);
      return;
    }

    let currentIndex = 0;
    let currentCharacterCount = 0;
    let currentElementStartedAt = 0;
    let timerId: number | null = null;
    let isCancelled = false;

    setStreamedElementList([]);

    const streamNextFrame = () => {
      if (isCancelled || currentIndex >= stableElementList.length) {
        return;
      }

      const currentElement = stableElementList[currentIndex];
      const completedElementList = stableElementList
        .slice(0, currentIndex)
        .map((element) => buildStreamedElement(element, element.content, true));

      if (
        !canStreamElementContent(currentElement) ||
        currentElement.content.length === 0
      ) {
        setStreamedElementList([
          ...completedElementList,
          buildStreamedElement(
            currentElement,
            currentElement.content,
            true,
            currentElement.audio_segments?.length ?? 0
          ),
        ]);
        currentIndex += 1;
        currentElementStartedAt = 0;

        if (currentIndex >= stableElementList.length) {
          return;
        }

        timerId = window.setTimeout(streamNextFrame, STREAM_ELEMENT_PAUSE_MS);
        return;
      }

      if (currentElementStartedAt === 0) {
        currentElementStartedAt = Date.now();
      }

      const nextCharacterCount = Math.min(
        currentCharacterCount + 1,
        currentElement.content.length
      );
      const isContentComplete =
        nextCharacterCount >= currentElement.content.length;
      const elapsedMs = Date.now() - currentElementStartedAt;
      const totalAudioSegmentCount = currentElement.audio_segments?.length ?? 0;
      const visibleAudioSegmentCount = getVisibleAudioSegmentCount(
        currentElement,
        elapsedMs
      );
      const isAudioSegmentStreamingComplete =
        !shouldStreamAudioSegments(currentElement) ||
        visibleAudioSegmentCount >= totalAudioSegmentCount;
      const isElementComplete =
        isContentComplete && isAudioSegmentStreamingComplete;

      setStreamedElementList([
        ...completedElementList,
        buildStreamedElement(
          currentElement,
          currentElement.content.slice(0, nextCharacterCount),
          isElementComplete,
          visibleAudioSegmentCount
        ),
      ]);

      if (isElementComplete) {
        currentIndex += 1;
        currentCharacterCount = 0;
        currentElementStartedAt = 0;

        if (currentIndex >= stableElementList.length) {
          return;
        }

        timerId = window.setTimeout(streamNextFrame, STREAM_ELEMENT_PAUSE_MS);
        return;
      }

      currentCharacterCount = nextCharacterCount;
      timerId = window.setTimeout(
        streamNextFrame,
        isContentComplete
          ? getNextAudioSegmentDelay(
              currentElement,
              elapsedMs,
              visibleAudioSegmentCount
            )
          : getStreamCharacterDelay(currentElement)
      );
    };

    timerId = window.setTimeout(streamNextFrame, STREAM_INITIAL_DELAY_MS);

    return () => {
      isCancelled = true;

      if (timerId !== null) {
        window.clearTimeout(timerId);
      }
    };
  }, [stableElementList]);
  return <Slide {...props} elementList={streamedElementList} />;
};

const RUN_STREAM_EVENT_INTERVAL_MS = 180;

const parseRunStreamFixture = (rawText: string): RunStreamFixtureEvent[] =>
  rawText
    .split(/\r?\n/)
    .filter((line) => line.startsWith("data: "))
    .map((line) => line.slice(6).trim())
    .flatMap((payload) => {
      if (!payload) {
        return [];
      }

      try {
        return [JSON.parse(payload) as RunStreamFixtureEvent];
      } catch {
        return [];
      }
    });

const parseHistoryFixture = (rawText: string): Element[] => {
  try {
    const parsedFixture = JSON.parse(rawText) as Element[];

    return Array.isArray(parsedFixture) ? parsedFixture : [];
  } catch {
    return [];
  }
};

const getLatestInteractionIndex = (elementList: Element[]) =>
  elementList.reduce(
    (latestIndex, element, index) =>
      element.type === "interaction" ? index : latestIndex,
    -1
  );

const focusHistoryOnLatestInteraction = (elementList: Element[]) => {
  const latestInteractionIndex = getLatestInteractionIndex(elementList);

  if (latestInteractionIndex < 0) {
    return elementList;
  }

  return elementList.map((element, index) => {
    if (!element.is_marker) {
      return element;
    }

    return {
      ...element,
      is_renderable: index === latestInteractionIndex,
    };
  });
};

const resolveSubmittedUserInput = (content: OnSendContentParams) =>
  [
    ...(content.selectedValues ?? []),
    content.inputText?.trim() ?? "",
    content.buttonText?.trim() ?? "",
  ]
    .filter(Boolean)
    .join(", ");

const isSameStoryElement = (currentElement: Element, targetElement?: Element) =>
  Boolean(
    targetElement &&
    currentElement.type === targetElement.type &&
    currentElement.sequence_number === targetElement.sequence_number &&
    currentElement.content === targetElement.content
  );

const applyInteractionSubmission = (
  elementList: Element[],
  targetElement: Element | undefined,
  submittedUserInput: string
) => {
  if (!submittedUserInput) {
    return elementList;
  }

  const fallbackInteractionIndex = getLatestInteractionIndex(elementList);

  return elementList.map((element, index) => {
    const shouldUpdateElement = targetElement
      ? isSameStoryElement(element, targetElement)
      : index === fallbackInteractionIndex;

    if (!shouldUpdateElement) {
      return element;
    }

    return {
      ...element,
      user_input: submittedUserInput,
      readonly: true,
    };
  });
};

const applyRunStreamInteractionSubmission = (
  elementList: RunStreamFixtureElement[],
  targetElement: Element | undefined,
  submittedUserInput: string
) =>
  applyInteractionSubmission(
    elementList,
    targetElement,
    submittedUserInput
  ) as RunStreamFixtureElement[];

const buildTriggeredRunStreamEvents = (events: RunStreamFixtureEvent[]) => {
  const triggerEventIndex = events.findIndex((event) => {
    const eventContent = event.content;

    return (
      event?.type === "element" &&
      eventContent?.element_type === "text" &&
      typeof eventContent.content === "string" &&
      eventContent.content.includes("三个观点你都不同意")
    );
  });

  if (triggerEventIndex < 0) {
    return [];
  }

  return events.slice(triggerEventIndex);
};

const EMPTY_PPT_PLACEHOLDER_BLOCK_BID = "empty-ppt";

const isEmptyPptPlaceholderElement = (element?: Element) =>
  (element as { blockBid?: string } | undefined)?.blockBid ===
  EMPTY_PPT_PLACEHOLDER_BLOCK_BID;

const createEmptyPptPlaceholderElement = (sequenceNumber: number): Element =>
  ({
    sequence_number: sequenceNumber,
    type: "slot",
    content: (
      <div className="flex h-full w-full items-center justify-center text-center text-[40px] font-bold leading-[1.3] text-primary">
        empty-ppt
      </div>
    ),
    is_marker: true,
    is_renderable: true,
    is_new: true,
    is_speakable: false,
    audio_url: "",
    audio_segments: [],
    blockBid: EMPTY_PPT_PLACEHOLDER_BLOCK_BID,
    page: 0,
  }) as Element;

const prependEmptyPptPlaceholderForLeadingText = (elementList: Element[]) => {
  if (elementList.length === 0) {
    return elementList;
  }

  const hasEmptyPptPlaceholder = elementList.some((element) =>
    isEmptyPptPlaceholderElement(element)
  );
  if (hasEmptyPptPlaceholder) {
    return elementList;
  }

  const firstContentElementIndex = elementList.findIndex(
    (element) =>
      element.type !== "interaction" && !isEmptyPptPlaceholderElement(element)
  );
  const firstContentElement =
    firstContentElementIndex >= 0
      ? elementList[firstContentElementIndex]
      : null;
  if (!firstContentElement || firstContentElement.type !== "text") {
    return elementList;
  }

  const firstSequenceNumber = Number(elementList[0]?.sequence_number ?? 1);

  return [
    createEmptyPptPlaceholderElement(Math.max(firstSequenceNumber - 1, 0)),
    ...elementList,
  ];
};

type RunStreamSlidePreviewProps = React.ComponentProps<typeof Slide> & {
  prependEmptyPptPlaceholder?: boolean;
};

const createRunStreamEventPlayback = ({
  events,
  sequenceMapRef,
  setElementList,
}: {
  events: RunStreamFixtureEvent[];
  sequenceMapRef: React.MutableRefObject<Map<string, number>>;
  setElementList: React.Dispatch<
    React.SetStateAction<RunStreamFixtureElement[]>
  >;
}) => {
  let currentEventIndex = 0;
  let timerId: number | null = null;
  let isCancelled = false;

  sequenceMapRef.current.clear();
  setElementList([]);

  const emitNextEvent = () => {
    if (isCancelled || currentEventIndex >= events.length) {
      return;
    }

    const currentEvent = events[currentEventIndex];
    currentEventIndex += 1;

    if (currentEvent?.type === "element" && currentEvent.content) {
      const nextElement = normalizeRunStreamElement(
        currentEvent.content,
        Number(currentEvent.run_event_seq ?? 0)
      );

      if (nextElement) {
        setElementList((prevElementList) =>
          upsertRunStreamElementList({
            currentList: prevElementList,
            nextElement,
            sequenceMap: sequenceMapRef.current,
          })
        );
      }
    }

    if (currentEventIndex >= events.length) {
      return;
    }

    timerId = window.setTimeout(emitNextEvent, RUN_STREAM_EVENT_INTERVAL_MS);
  };

  timerId = window.setTimeout(emitNextEvent, STREAM_INITIAL_DELAY_MS);

  return () => {
    isCancelled = true;

    if (timerId !== null) {
      window.clearTimeout(timerId);
    }
  };
};

const RunStreamSlidePreview = ({
  elementList = [],
  prependEmptyPptPlaceholder = true,
  ...props
}: RunStreamSlidePreviewProps) => {
  const [streamedElementList, setStreamedElementList] = useState<
    RunStreamFixtureElement[]
  >([]);
  const runStreamSequenceByKeyRef = useRef<Map<string, number>>(new Map());
  const runStreamEvents = useMemo(
    () => parseRunStreamFixture(runStreamFixtureText),
    []
  );
  const fallbackElementList = useMemo(() => elementList, [elementList]);
  const applyRunStreamElementListTransform = useCallback(
    (nextElementList: Element[]) =>
      prependEmptyPptPlaceholder
        ? prependEmptyPptPlaceholderForLeadingText(nextElementList)
        : nextElementList,
    [prependEmptyPptPlaceholder]
  );

  const displayElementList = useMemo(
    () =>
      applyRunStreamElementListTransform(
        runStreamEvents.length === 0 ? fallbackElementList : streamedElementList
      ),
    [
      applyRunStreamElementListTransform,
      fallbackElementList,
      runStreamEvents.length,
      streamedElementList,
    ]
  );

  useEffect(() => {
    if (runStreamEvents.length === 0) {
      setStreamedElementList([]);
      return;
    }

    return createRunStreamEventPlayback({
      events: runStreamEvents,
      sequenceMapRef: runStreamSequenceByKeyRef,
      setElementList: setStreamedElementList,
    });
  }, [runStreamEvents]);

  console.log("streamedElementList", displayElementList);

  return <Slide {...props} elementList={displayElementList} />;
};

const historyInteractionFixtureElementList = focusHistoryOnLatestInteraction(
  parseHistoryFixture(historyFixtureText)
);

const triggeredRunStreamEvents = buildTriggeredRunStreamEvents(
  parseRunStreamFixture(runStreamFixtureText)
);

const hasAudioDataSegments = (audioSegments: Element["audio_segments"]) =>
  Boolean(
    audioSegments?.some(
      (segment) =>
        typeof segment?.audio_data === "string" && segment.audio_data.length > 0
    )
  );

const getAudioDataSrc = (audioData: string) => {
  const normalizedAudioData = audioData.trim();

  if (!normalizedAudioData) {
    return "";
  }

  if (/^data:audio\//i.test(normalizedAudioData)) {
    return normalizedAudioData;
  }

  return `data:audio/mpeg;base64,${normalizedAudioData}`;
};

const runStreamFixtureElementList = buildRunStreamElementListFromEvents({
  events: parseRunStreamFixture(runStreamFixtureText),
  sequenceMap: new Map<string, number>(),
});

const audioSegmentsPlaybackElementList: Element[] = runStreamFixtureElementList
  .filter(
    (element) =>
      element.type === "text" &&
      Boolean(element.is_speakable) &&
      hasAudioDataSegments(element.audio_segments)
  )
  .map((element, index) => ({
    ...element,
    sequence_number: index + 1,
    is_marker: true,
    is_renderable: true,
    is_new: index === 0,
    audio_url: "",
  }));

type AudioSegmentsPlaybackItem = {
  id: string;
  elementSequenceNumber: number;
  segmentIndex: number;
  durationMs: number;
  isFinal: boolean;
  contentPreview: string;
  audioSrc: string;
};

const AudioSegmentsPlaybackPreview = ({
  elementList = [],
}: {
  elementList?: Element[];
}) => {
  const playbackItemList = useMemo(
    () =>
      elementList.flatMap((element, elementIndex) => {
        const sequenceNumber = Number(
          element.sequence_number ?? elementIndex + 1
        );
        const contentPreview =
          typeof element.content === "string"
            ? element.content.slice(0, 120)
            : "";

        return (element.audio_segments ?? [])
          .filter(
            (segment) =>
              typeof segment?.audio_data === "string" &&
              segment.audio_data.length > 0
          )
          .map<AudioSegmentsPlaybackItem>((segment, segmentOrder) => ({
            id: [
              String(element.type),
              String(sequenceNumber),
              String(segment.segment_index ?? segmentOrder),
            ].join(":"),
            elementSequenceNumber: sequenceNumber,
            segmentIndex: Number(segment.segment_index ?? segmentOrder),
            durationMs: Number(segment.duration_ms ?? 0),
            isFinal: Boolean(segment.is_final),
            contentPreview,
            audioSrc: getAudioDataSrc(segment.audio_data),
          }))
          .filter((item) => Boolean(item.audioSrc));
      }),
    [elementList]
  );

  console.log("audioSegmentsPlaybackItems", playbackItemList);

  if (playbackItemList.length === 0) {
    return (
      <div className="flex min-h-[100dvh] w-full items-center justify-center px-6 text-sm text-muted-foreground">
        No playable audio_data segments found in elementList.
      </div>
    );
  }

  return (
    <div className="mx-auto flex min-h-[100dvh] w-full max-w-5xl flex-col gap-4 px-4 py-6 md:px-6">
      {playbackItemList.map((item) => (
        <section
          key={item.id}
          className="rounded-lg border border-border bg-card p-4"
        >
          <div className="mb-3 flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-muted-foreground">
            <span>{`Element #${item.elementSequenceNumber}`}</span>
            <span>{`Segment #${item.segmentIndex}`}</span>
            <span>{`Duration ${item.durationMs}ms`}</span>
            <span>{item.isFinal ? "Final segment" : "Streaming segment"}</span>
          </div>
          <audio
            className="w-full"
            controls
            preload="metadata"
            src={item.audioSrc}
          >
            Your browser does not support the audio element.
          </audio>
          {item.contentPreview ? (
            <p className="mt-2 line-clamp-2 text-xs text-muted-foreground">
              {item.contentPreview}
            </p>
          ) : null}
        </section>
      ))}
    </div>
  );
};

const HistoryInteractionTriggeredRunStreamSlidePreview = ({
  elementList = [],
  onSend,
  ...props
}: React.ComponentProps<typeof Slide>) => {
  const stableHistoryElementList = useMemo(
    () => focusHistoryOnLatestInteraction(elementList),
    [elementList]
  );
  const [historyElementList, setHistoryElementList] = useState<Element[]>(
    stableHistoryElementList
  );
  const [streamedElementList, setStreamedElementList] = useState<
    RunStreamFixtureElement[]
  >([]);
  const runStreamSequenceByKeyRef = useRef<Map<string, number>>(new Map());
  const [streamSessionCount, setStreamSessionCount] = useState(0);

  useEffect(() => {
    setHistoryElementList(stableHistoryElementList);
    setStreamedElementList([]);
    runStreamSequenceByKeyRef.current.clear();
    setStreamSessionCount(0);
  }, [stableHistoryElementList]);

  useEffect(() => {
    if (streamSessionCount === 0 || triggeredRunStreamEvents.length === 0) {
      return;
    }

    return createRunStreamEventPlayback({
      events: triggeredRunStreamEvents,
      sequenceMapRef: runStreamSequenceByKeyRef,
      setElementList: setStreamedElementList,
    });
  }, [streamSessionCount]);

  const handleSend = useCallback(
    (content: OnSendContentParams, element?: Element) => {
      console.log("onsend", content, element);
      onSend?.(content, element);

      const submittedUserInput = resolveSubmittedUserInput(content);

      setHistoryElementList((prevElementList) =>
        applyInteractionSubmission(
          prevElementList,
          element,
          submittedUserInput || "都不同意"
        )
      );
      setStreamedElementList([]);
      setStreamSessionCount((prevCount) => prevCount + 1);
    },
    [onSend]
  );

  const mergedElementList = useMemo(
    () => [...historyElementList, ...streamedElementList],
    [historyElementList, streamedElementList]
  );

  console.log("mergedElementList", mergedElementList);

  return (
    <Slide {...props} elementList={mergedElementList} onSend={handleSend} />
  );
};

const FixtureSwitchInteractionTriggeredRunStreamSlidePreview = ({
  onSend,
  prependEmptyPptPlaceholder = true,
  ...props
}: React.ComponentProps<typeof Slide> & {
  prependEmptyPptPlaceholder?: boolean;
}) => {
  const initialRunStreamEvents = useMemo(
    () => parseRunStreamFixture(runStreamFixtureText2),
    []
  );
  const followUpRunStreamEvents = useMemo(
    () => parseRunStreamFixture(runStreamFixtureText),
    []
  );
  const [initialStreamedElementList, setInitialStreamedElementList] = useState<
    RunStreamFixtureElement[]
  >([]);
  const [followUpStreamedElementList, setFollowUpStreamedElementList] =
    useState<RunStreamFixtureElement[]>([]);
  const initialRunStreamSequenceByKeyRef = useRef<Map<string, number>>(
    new Map()
  );
  const followUpRunStreamSequenceByKeyRef = useRef<Map<string, number>>(
    new Map()
  );
  const [followUpStreamSessionCount, setFollowUpStreamSessionCount] =
    useState(0);
  const applyRunStreamElementListTransform = useCallback(
    (nextElementList: Element[]) =>
      prependEmptyPptPlaceholder
        ? prependEmptyPptPlaceholderForLeadingText(nextElementList)
        : nextElementList,
    [prependEmptyPptPlaceholder]
  );

  useEffect(() => {
    setFollowUpStreamSessionCount(0);
    setFollowUpStreamedElementList([]);
    followUpRunStreamSequenceByKeyRef.current.clear();

    if (initialRunStreamEvents.length === 0) {
      setInitialStreamedElementList([]);
      return;
    }

    return createRunStreamEventPlayback({
      events: initialRunStreamEvents,
      sequenceMapRef: initialRunStreamSequenceByKeyRef,
      setElementList: setInitialStreamedElementList,
    });
  }, [initialRunStreamEvents]);

  useEffect(() => {
    if (
      followUpStreamSessionCount === 0 ||
      followUpRunStreamEvents.length === 0
    ) {
      return;
    }

    return createRunStreamEventPlayback({
      events: followUpRunStreamEvents,
      sequenceMapRef: followUpRunStreamSequenceByKeyRef,
      setElementList: setFollowUpStreamedElementList,
    });
  }, [followUpRunStreamEvents, followUpStreamSessionCount]);

  const handleSend = useCallback(
    (content: OnSendContentParams, element?: Element) => {
      console.log("onsend", content, element);
      onSend?.(content, element);

      const submittedUserInput = resolveSubmittedUserInput(content);

      setInitialStreamedElementList((prevElementList) =>
        applyRunStreamInteractionSubmission(
          prevElementList,
          element,
          submittedUserInput || "非常了解"
        )
      );
      setFollowUpStreamSessionCount((prevCount) => prevCount + 1);
    },
    [onSend]
  );

  const mergedElementList = useMemo(
    () =>
      applyRunStreamElementListTransform([
        ...initialStreamedElementList,
        ...followUpStreamedElementList,
      ]),
    [
      applyRunStreamElementListTransform,
      followUpStreamedElementList,
      initialStreamedElementList,
    ]
  );

  console.log("fixtureSwitchMergedElementList", mergedElementList);

  return (
    <Slide {...props} elementList={mergedElementList} onSend={handleSend} />
  );
};

