    // elementList: [
    //   {
    //     sequence_number: 110,
    //     type: "html",
    //     content:
    //       '<div id="ppt-container" class="w-full min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50 p-[4vmin] font-[\'system-ui\',\'-apple-system\',\'Segoe_UI\',\'Roboto\',\'sans-serif\']">\n  <div class="w-full h-screen flex flex-col items-center justify-[safe_center] gap-[4vmin] p-[4vmin] overflow-y-auto">\n    <!-- 顶部标题区 -->\n    <div class="w-full max-w-[1200px] text-center">\n      <h1 class="text-[6vmin] font-bold text-[#0F63EE] mb-[2vmin]">三大考勤流程，一次搞定</h1>\n      <p class="text-[3vmin] text-gray-700">本节开场总览图</p>\n    </div>\n\n    <!-- 目标说明区 -->\n    <div class="w-full max-w-[1200px] bg-white rounded-[2vmin] shadow-lg p-[5vmin]">\n      <h2 class="text-[4vmin] font-bold text-gray-800 mb-[3vmin]">本节目标</h2>\n      <p class="text-[2.5vmin] text-gray-700 leading-[3.5vmin]">\n        学会在 <strong>UNKNOWN</strong> 系统内，完成请假、公出、加班等考勤流程的发起与处理，做到“<strong>上级同意</strong>、<strong>当月务必发起流程</strong>、<strong>材料齐全</strong>”。\n      </p>\n    </div>\n\n    <!-- 三流程概览区 -->\n    <div class="w-full max-w-[1200px]">\n      <h2 class="text-[4vmin] font-bold text-gray-800 mb-[4vmin] text-center">三大核心流程概览</h2>\n      <div class="grid grid-cols-1 md:grid-cols-3 gap-[4vmin]">\n        <!-- 请假流程卡片 -->\n        <div class="bg-white rounded-[2vmin] shadow-lg p-[4vmin] flex flex-col items-center text-center border-t-4 border-[#0F63EE]">\n          <div class="w-[12vmin] h-[12vmin] rounded-full bg-blue-100 flex items-center justify-center mb-[3vmin]">\n            <span class="text-[5vmin]">📅</span>\n          </div>\n          <h3 class="text-[3.5vmin] font-bold text-gray-800 mb-[2vmin]">请假流程</h3>\n          <p class="text-[2.5vmin] text-gray-600 flex-grow">因个人事务或身体原因，需要申请离开工作岗位的流程。</p>\n        </div>\n        <!-- 公出流程卡片 -->\n        <div class="bg-white rounded-[2vmin] shadow-lg p-[4vmin] flex flex-col items-center text-center border-t-4 border-[#0F63EE]">\n          <div class="w-[12vmin] h-[12vmin] rounded-full bg-blue-100 flex items-center justify-center mb-[3vmin]">\n            <span class="text-[5vmin]">✈️</span>\n          </div>\n          <h3 class="text-[3.5vmin] font-bold text-gray-800 mb-[2vmin]">公出流程</h3>\n          <p class="text-[2.5vmin] text-gray-600 flex-grow">因公务需要，离开常驻办公地点外出办事或出差的流程。</p>\n        </div>\n        <!-- 加班流程卡片 -->\n        <div class="bg-white rounded-[2vmin] shadow-lg p-[4vmin] flex flex-col items-center text-center border-t-4 border-[#0F63EE]">\n          <div class="w-[12vmin] h-[12vmin] rounded-full bg-blue-100 flex items-center justify-center mb-[3vmin]">\n            <span class="text-[5vmin]">💼</span>\n          </div>\n          <h3 class="text-[3.5vmin] font-bold text-gray-800 mb-[2vmin]">加班流程</h3>\n          <p class="text-[2.5vmin] text-gray-600 flex-grow">在法定工作时间外，因工作需要申请延长工作时间的流程。</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- 核心原则区 -->\n    <div class="w-full max-w-[1200px] bg-gradient-to-r from-[#0F63EE] to-blue-600 rounded-[2vmin] shadow-xl p-[5vmin] text-white">\n      <h2 class="text-[4vmin] font-bold mb-[4vmin] text-center">必须牢记的三大核心原则</h2>\n      <div class="grid grid-cols-1 md:grid-cols-3 gap-[4vmin]">\n        <div class="bg-white/20 rounded-[1.5vmin] p-[3vmin] backdrop-blur-sm">\n          <div class="text-[3.5vmin] font-bold mb-[2vmin] flex items-center justify-center">\n            <span class="mr-[2vmin]">✅</span> 上级同意\n          </div>\n          <p class="text-[2.5vmin]">任何考勤流程发起前，务必先获得直接主管的知晓与批准。</p>\n        </div>\n        <div class="bg-white/20 rounded-[1.5vmin] p-[3vmin] backdrop-blur-sm">\n          <div class="text-[3.5vmin] font-bold mb-[2vmin] flex items-center justify-center">\n            <span class="mr-[2vmin]">📆</span> 当月发起\n          </div>\n          <p class="text-[2.5vmin]">所有流程务必在考勤发生的当月内发起，避免跨月补单。</p>\n        </div>\n        <div class="bg-white/20 rounded-[1.5vmin] p-[3vmin] backdrop-blur-sm">\n          <div class="text-[3.5vmin] font-bold mb-[2vmin] flex items-center justify-center">\n            <span class="mr-[2vmin]">📎</span> 材料齐全\n          </div>\n          <p class="text-[2.5vmin]">根据流程类型，提前准备好病假条、出差申请单等证明材料。</p>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<style>\n  /* 确保在小屏幕下流程卡片纵向堆叠 */\n  @media (max-width: 768px) {\n    #ppt-container .grid-cols-3 {\n      grid-template-columns: 1fr !important;\n    }\n    /* 适当调整小屏幕下的内边距和字号，确保文字完整 */\n    #ppt-container .p-\\[4vmin\\] {\n      padding: 3vmin;\n    }\n    #ppt-container .text-\\[2\\.5vmin\\] {\n      font-size: 2.8vmin;\n    }\n  }\n  /* 基础样式确保文字不被裁切 */\n  #ppt-container * {\n    box-sizing: border-box;\n  }\n  #ppt-container p, #ppt-container h1, #ppt-container h2, #ppt-container h3 {\n    overflow-wrap: break-word;\n    word-wrap: break-word;\n    hyphens: auto;\n  }\n</style>\n\n',
